import React, { useState, useEffect } from "react";
import io from "socket.io-client";
import {
  Button,
  TextField,
  Box,
  Paper,
  Typography,
  List,
  ListItem,
  ListItemText,
  Grid,
} from "@mui/material";

const Chat = () => {
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState("");
  const [roomName, setRoomName] = useState("");
  const [socket, setSocket] = useState(null);

  useEffect(() => {
    const newSocket = io("http://localhost:3000");
    setSocket(newSocket);

    newSocket.on("message", (message) => {
      setMessages((prevMessages) => [...prevMessages, message]);
    });

    newSocket.on("recentMessages", (recentMessages) => {
      setMessages(recentMessages);
    });

    newSocket.on("roomError", (error) => {
      console.error("Room error:", error);
    });

    return () => newSocket.close();
  }, []);

  const createRoom = () => {
    if (roomName && socket) {
      socket.emit("createRoom", roomName);
    }
  };

  const joinRoom = () => {
    if (roomName && socket) {
      socket.emit("joinRoom", roomName);
    }
  };

  const leaveRoom = () => {
    if (roomName && socket) {
      socket.emit("leaveRoom", roomName);
      setRoomName("");
      setMessages([]);
    }
  };

  const sendMessage = (e) => {
    e.preventDefault();
    if (inputMessage && socket && roomName) {
      socket.emit("sendMessage", { room: roomName, message: inputMessage });
      setInputMessage("");
    }
  };

  return (
    <Box sx={{ maxWidth: 600, margin: "auto", mt: 4 }}>
      <Paper elevation={3} sx={{ p: 3 }}>
        <Typography variant="h5" gutterBottom>
          聊天室
        </Typography>
        <Grid container spacing={2} sx={{ mb: 2 }}>
          <Grid item xs={12} sm={6}>
            <TextField
              fullWidth
              value={roomName}
              onChange={(e) => setRoomName(e.target.value)}
              placeholder="輸入房間名"
              variant="outlined"
              size="small"
            />
          </Grid>
          <Grid item xs={12} sm={6}>
            <Box sx={{ display: "flex", gap: 1 }}>
              <Button variant="contained" onClick={createRoom} size="small">
                建立房間
              </Button>
              <Button variant="contained" onClick={joinRoom} size="small">
                加入房間
              </Button>
              <Button variant="outlined" onClick={leaveRoom} size="small">
                離開房間
              </Button>
            </Box>
          </Grid>
        </Grid>
        <Paper
          variant="outlined"
          sx={{ height: 300, overflow: "auto", mb: 2, p: 2 }}
        >
          <List>
            {messages.map((message, index) => (
              <ListItem key={index}>
                <ListItemText primary={message.text} />
              </ListItem>
            ))}
          </List>
        </Paper>
        <Box
          component="form"
          onSubmit={sendMessage}
          sx={{ display: "flex", gap: 1 }}
        >
          <TextField
            fullWidth
            value={inputMessage}
            onChange={(e) => setInputMessage(e.target.value)}
            placeholder="輸入消息"
            variant="outlined"
            size="small"
          />
          <Button type="submit" variant="contained">
            發送
          </Button>
        </Box>
      </Paper>
    </Box>
  );
};

export default Chat;
